const sleep=(ms)=>new Promise(r=>setTimeout(r,ms));
function getRarity(){let r=Math.random()*100,a=0;for(const rt of RARITIES){a+=rt.weight;if(r<a)return rt;}return RARITIES[0];}
let _tc=1;
function mintTicket(pid){return{id:`WP-${pid.toUpperCase()}-${String(_tc++).padStart(4,"0")}`,poolId:pid,status:"LIVE",ts:Date.now()};}
function stackR(results){const m={};results.forEach(r=>{const id=r.ticket.id;if(!m[id])m[id]={ticket:r.ticket,prizes:[],totalEth:0};m[id].prizes.push(r);m[id].totalEth+=parseFloat(r.ethWon);});return Object.values(m).sort((a,b)=>b.prizes.length-a.prizes.length||b.totalEth-a.totalEth);}
function genDemo(pid){return[...Array(13).fill("Common"),...Array(8).fill("Uncommon"),...Array(5).fill("Rare"),...Array(3).fill("Epic"),...Array(1).fill("Legendary")].map((rn,i)=>{const rarity=RARITIES.find(r=>r.name===rn)||RARITIES[0];return{id:`DEMO-${pid.toUpperCase()}-${String(i+1).padStart(3,"0")}`,poolId:pid,rarity,skin:SKINS[i%6],hat:HATS[i%6],acc:ACCS[i%6],status:"LIVE",addr:`0x${(0xA000+i).toString(16)}...${(0xB000+i).toString(16)}`};});}
function getNextSpin(ih,om){const n=Date.now(),im=ih*3600000,o2=om*60000,dm=86400000,b=Math.floor(n/dm)*dm;for(let i=0;i<=Math.ceil(24/ih)+2;i++){const t=b+i*im+o2;if(t>n+500)return t;}return b+dm+o2;}
function fmtMs(ms){if(ms<=0)return"00:00:00";const d=Math.floor(ms/86400000),h=Math.floor((ms%86400000)/3600000),m=Math.floor((ms%3600000)/60000),s=Math.floor((ms%60000)/1000);const t=`${String(h).padStart(2,"0")}:${String(m).padStart(2,"0")}:${String(s).padStart(2,"0")}`;return d>0?`${d}d ${t}`:t;}

/* ══════════════════════════════════════════════
   INTERACTIVE WHEEL — replaces the static image wheel
══════════════════════════════════════════════ */
function SpinFX({active,size}){
  if(!active)return null;
  const sparks=[
    {a:0,  d:90, c:"#1BF26A",s:7,dl:"0s"},
    {a:30, d:110,c:"#FFDD00",s:5,dl:"0.05s"},
    {a:60, d:95, c:"#44FF44",s:8,dl:"0.1s"},
    {a:90, d:115,c:"#FFE944",s:5,dl:"0.02s"},
    {a:120,d:100,c:"#1BF26A",s:6,dl:"0.08s"},
    {a:150,d:90, c:"#FFDD00",s:9,dl:"0.04s"},
    {a:180,d:108,c:"#44FF44",s:5,dl:"0.12s"},
    {a:210,d:95, c:"#1BF26A",s:7,dl:"0.06s"},
    {a:240,d:112,c:"#FFE944",s:6,dl:"0s"},
    {a:270,d:90, c:"#FFDD00",s:8,dl:"0.09s"},
    {a:300,d:105,c:"#1BF26A",s:5,dl:"0.03s"},
    {a:330,d:98, c:"#44FF44",s:7,dl:"0.07s"},
  ];
  return(
    <div style={{position:"absolute",inset:0,pointerEvents:"none",zIndex:20,overflow:"visible"}}>
      {/* expanding rings */}
      {[0,1,2].map(function(i){return(
        <div key={"r"+i} style={{
          position:"absolute",
          left:size/2-size*0.45, top:size/2-size*0.45,
          width:size*0.9, height:size*0.9,
          borderRadius:"50%",
          border:"3px solid #1BF26A",
          opacity:0.8,
          animation:"ringPulse 1.1s ease-out "+(i*0.28)+"s forwards",
        }}/> );
      })}
      {/* spark dots — positioned at destination, bloom then fade */}
      {sparks.map(function(sp,i){
        var rad=sp.a*Math.PI/180;
        var ex=Math.round(Math.cos(rad)*sp.d);
        var ey=Math.round(Math.sin(rad)*sp.d);
        return(
          <div key={"sp"+i} style={{
            position:"absolute",
            left:"calc(50% + "+ex+"px)",
            top:"calc(50% + "+ey+"px)",
            width:sp.s, height:sp.s,
            borderRadius:"50%",
            background:sp.c,
            boxShadow:"0 0 "+(sp.s*2)+"px "+sp.c,
            transform:"translate(-50%,-50%)",
            animation:"sparkFade "+Number(0.65+i*0.04).toFixed(2)+"s ease-out "+sp.dl+" forwards",
          }}/>
        );
      })}
    </div>
  );
}

function InteractiveWheel({size=300}){
  const[angle,setAngle]=useState(0);
  const[spinning,setSpinning]=useState(false);
  const[label,setLabel]=useState("CLICK TO SPIN");
  const[showFX,setShowFX]=useState(false);
  const N=WHEEL_SEGS.length,cx=size/2,cy=size/2,r=size/2-18;

  const seg=(i)=>{
    const a1=(i/N)*2*Math.PI-Math.PI/2,a2=((i+1)/N)*2*Math.PI-Math.PI/2;
    return`M${cx},${cy} L${cx+r*Math.cos(a1)},${cy+r*Math.sin(a1)} A${r},${r} 0 0,1 ${cx+r*Math.cos(a2)},${cy+r*Math.sin(a2)}Z`;
  };
  const tp=(i)=>{const a=((i+.5)/N)*2*Math.PI-Math.PI/2;return{x:cx+r*.68*Math.cos(a),y:cy+r*.68*Math.sin(a)};};

  const spin=()=>{
    if(spinning)return;
    setSpinning(true);
    setShowFX(true);
    setLabel("SPINNING...");
    const extra=3240+Math.random()*1440; // 9-13 full rotations
    setAngle(a=>a+extra);
    setTimeout(()=>setShowFX(false),1400); // FX last 1.4s
    setTimeout(()=>{setSpinning(false);setLabel("SPIN AGAIN!");},7200);
  };

  return(
    <div style={{position:"relative",display:"inline-block",cursor:spinning?"default":"pointer"}} onClick={spin}>
      <div style={{position:"absolute",top:-6,left:"50%",transform:"translateX(-50%)",
        fontSize:size/14,color:"#FF4444",textShadow:"0 0 12px #FF4444",zIndex:5,lineHeight:1}}>▼</div>

      {/* outer glow ring — pulses faster during spin */}
      <div style={{
        position:"absolute",inset:-10,borderRadius:"50%",
        border:`3px solid ${spinning?"#1BF26A":"rgba(27,242,106,.25)"}`,
        boxShadow:spinning
          ?"0 0 30px #1BF26A, 0 0 60px rgba(27,242,106,.5)"
          :"0 0 12px rgba(27,242,106,.2)",
        transition:"box-shadow .3s, border-color .3s",
        pointerEvents:"none",
      }}/>

      {/* particle FX overlay */}
      <SpinFX active={showFX} size={size}/>

      <svg width={size} height={size} style={{
        transform:`rotate(${angle}deg)`,
        transition:spinning?`transform 7.2s cubic-bezier(0.22,1,0.36,1)`:"none",
        filter:spinning
          ?"drop-shadow(0 0 28px rgba(27,242,106,.9)) drop-shadow(0 0 8px #FFD700)"
          :"drop-shadow(0 0 14px rgba(27,242,106,.45))",
        display:"block",
      }}>
        <circle cx={cx} cy={cy} r={r+12} fill="#0a2e10"/>
        <circle cx={cx} cy={cy} r={r+8}  fill="#0d3e16"/>
        <circle cx={cx} cy={cy} r={r+4}  fill="#0b3314"/>
        {WHEEL_SEGS.map((s,i)=>(
          <g key={i}>
            <path d={seg(i)} fill={s.c} stroke="#000" strokeWidth="1.5"/>
            <text
              x={tp(i).x} y={tp(i).y}
              textAnchor="middle" dominantBaseline="middle"
              fill={s.c==="#FFDD00"||s.c==="#4ef08a"||s.c==="#6af5a8"?"#0a2e10":"#fff"}
              fontSize={String(s.v).length>6?Math.max(5,size/46):String(s.v).length>5?Math.max(6,size/40):Math.max(7,size/36)}
              fontFamily="'Press Start 2P',monospace"
              stroke={s.c==="#FFDD00"||s.c==="#4ef08a"||s.c==="#6af5a8"?"rgba(255,255,255,.3)":"rgba(0,0,0,.8)"}
              strokeWidth="2" paintOrder="stroke"
              transform={`rotate(${((i+0.5)/N*360-90)+(tp(i).x<cx?180:0)},${tp(i).x},${tp(i).y})`}
            >{s.v}</text>
          </g>
        ))}
        {WHEEL_SEGS.map((_,i)=>{
          const a=(i/N)*2*Math.PI-Math.PI/2;
          return<line key={`t${i}`}
            x1={cx+(r+2)*Math.cos(a)} y1={cy+(r+2)*Math.sin(a)}
            x2={cx+(r+9)*Math.cos(a)} y2={cy+(r+9)*Math.sin(a)}
            stroke="#1BF26A" strokeWidth="2"/>;
        })}
        <circle cx={cx} cy={cy} r={size/13} fill="#0a2e10" stroke="#1BF26A" strokeWidth="3"/>
        <circle cx={cx} cy={cy} r={size/20} fill="#1BF26A"/>
        <circle cx={cx} cy={cy} r={size/40} fill="#0a2e10"/>
      </svg>

      <div style={{
        position:"absolute",
        bottom:-28,left:"50%",transform:"translateX(-50%)",
        whiteSpace:"nowrap",
        color:spinning?"#FFDD00":"#1BF26A",
        fontSize:"clamp(10px,2vw,12px)",
        fontFamily:"'Press Start 2P',monospace",
        animation:spinning?"blinkAnim .5s infinite":"none",
        textShadow:"0 0 10px currentColor",
        background:"rgba(26,58,17,.75)",
        padding:"3px 8px",
        zIndex:10,
      }}>{label}</div>
    </div>
  );
}

