function DrawTheater({onClose,onPointsEarned,activePerks}){
  return <DrawTheaterFull onClose={onClose} onPointsEarned={onPointsEarned} activePerks={activePerks}/>;
}


function MintModal({pool,onClose,onMinted}){
  const[step,setStep]=useState("confirm");
  const[qty,setQty]=useState(1);
  const maxQty=10;
  const totalEth=(parseFloat(pool.entryEth||"0")*qty).toFixed(6);
  const totalUsd=(pool.entryUsd*qty).toFixed(0);

  const go=()=>{
    setStep("minting");
    setTimeout(()=>{
      const tickets=Array.from({length:qty},()=>mintTicket(pool.id));
      tickets.forEach(t=>onMinted(t));
      setStep("done");
    },1200);
  };

  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.88)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:500}} onClick={step==="confirm"?onClose:undefined}>
      <div onClick={e=>e.stopPropagation()} style={{
        background:"#145414",border:`3px solid ${pool.color}`,
        padding:"28px",maxWidth:360,width:"92%",
        boxShadow:`0 0 50px ${pool.glow}`,
        fontFamily:"'Press Start 2P',monospace",
      }}>

        {step==="confirm"&&<>
          <h3 style={{color:pool.color,fontSize:14,textAlign:"center",marginBottom:20}}>ENTER POOL</h3>

          {/* Pool summary */}
          <div style={{background:"#0f5422",border:`1px solid ${pool.color}44`,padding:16,marginBottom:16}}>
            <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:14,paddingBottom:12,borderBottom:`1px solid ${pool.color}33`}}>
              <span style={{fontSize:28}}>{pool.icon}</span>
              <div>
                <div style={{color:pool.color,fontSize:13,marginBottom:3}}>{pool.name}</div>
                <div style={{color:"#9de8b4",fontSize:9}}>{pool.label}</div>
              </div>
            </div>
            {/* Qty selector */}
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14,paddingBottom:12,borderBottom:`1px solid ${pool.color}22`}}>
              <span style={{color:"#9de8b4",fontSize:9,fontFamily:"'Press Start 2P',monospace"}}>QUANTITY</span>
              <div style={{display:"flex",alignItems:"center",gap:10}}>
                <button onClick={()=>setQty(q=>Math.max(1,q-1))} style={{
                  width:30,height:30,background:"#0a2010",color:pool.color,
                  border:`1px solid ${pool.color}`,cursor:"pointer",fontSize:16,outline:"none",
                }}>−</button>
                <span style={{color:pool.color,fontSize:22,fontFamily:"'VT323',monospace",minWidth:24,textAlign:"center"}}>{qty}</span>
                <button onClick={()=>setQty(q=>Math.min(maxQty,q+1))} style={{
                  width:30,height:30,background:"#0a2010",color:pool.color,
                  border:`1px solid ${pool.color}`,cursor:"pointer",fontSize:16,outline:"none",
                }}>+</button>
              </div>
            </div>

            {[
              ["ENTRY FEE",`${pool.entryEth} ETH × ${qty} = ${totalEth} ETH`,pool.color],
              ["TOTAL COST",`~$${totalUsd}`,"#FFDD00"],
              ["JACKPOT (50%)",`${(parseFloat(pool.poolEth)*0.45).toFixed(5)} ETH`,"#FFD700"],
              ["IN POOL NOW",`${pool.entries} entries`,"#9de8b4"],
              ["MIN TO DRAW","3 unique wallets","#9de8b4"],
            ].map(([l,v,c])=>(
              <div key={l} style={{display:"flex",justifyContent:"space-between",marginBottom:8,gap:8}}>
                <span style={{color:"#6aaa6a",fontSize:9,flexShrink:0}}>{l}</span>
                <span style={{color:c,fontSize:9,textAlign:"right"}}>{v}</span>
              </div>
            ))}
          </div>

          <div style={{background:"#0a2010",border:"1px solid #2a5a2a",padding:"10px 14px",marginBottom:16,fontSize:9,color:"#9de8b4",lineHeight:2}}>
            You pay your own gas to enter. If fewer than 3 unique wallets join, the draw is cancelled and you receive a full refund.
          </div>

          <div style={{display:"flex",gap:8}}>
            <button onClick={go} style={{flex:1,padding:13,background:"#1a6a28",color:"#fff",border:"none",cursor:"pointer",fontSize:11,borderBottom:`3px solid ${pool.color}`,outline:"none"}}>
              ENTER {qty > 1 ? `${qty} TICKETS` : "POOL"} → ${totalUsd}
            </button>
            <button onClick={onClose} style={{flex:1,padding:13,background:"#1a0808",color:"#888",border:"none",cursor:"pointer",fontSize:11,borderBottom:"3px solid #FF4444",outline:"none"}}>
              CANCEL
            </button>
          </div>
        </>}

        {step==="minting"&&(
          <div style={{textAlign:"center",padding:"36px 0"}}>
            <div style={{fontSize:32,marginBottom:20,animation:"spinAnim 1s linear infinite",display:"inline-block"}}>⏳</div>
            <div style={{color:pool.color,fontSize:12,letterSpacing:2,marginBottom:8}}>ENTERING POOL...</div>
            <div style={{color:"#9de8b4",fontSize:9,lineHeight:2}}>Submitting entry on Abstract Chain</div>
          </div>
        )}

        {step==="done"&&(
          <div style={{textAlign:"center",padding:"20px 0"}}>
            <div style={{fontSize:40,marginBottom:14}}>✅</div>
            <div style={{color:"#44FF44",fontSize:12,marginBottom:8}}>YOU&apos;RE IN!</div>
            <div style={{color:pool.color,fontSize:10,marginBottom:4}}>{pool.icon} {pool.name}</div>
            <div style={{color:"#9de8b4",fontSize:9,marginBottom:20,lineHeight:2}}>
              Entry confirmed. Draw runs {pool.label.toLowerCase()}.<br/>
              Winners paid automatically on-chain.
            </div>
            <button onClick={onClose} style={{
              width:"100%",padding:12,
              background:"#0a2a14",color:"#44FF44",
              border:`2px solid ${pool.color}`,
              cursor:"pointer",fontSize:10,
              fontFamily:"'Press Start 2P',monospace",outline:"none",
            }}>VIEW MY ENTRIES →</button>
          </div>
        )}

      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════
   POOL CARD
══════════════════════════════════════════════ */
function PoolCard({pool,msLeft,myTickets,onMint,onDraw,ethPrice=3000}){
  const[hov,setHov]=useState(false);
  const soon=msLeft<3600000,urgent=msLeft<300000;
  const mc=myTickets.length;
  const myOdds=mc>0?Math.min(99,(mc/pool.entries*100)).toFixed(1):null;
  return(<div onMouseEnter={()=>setHov(true)} onMouseLeave={()=>setHov(false)} style={{flex:"1 1 0",minWidth:0,maxWidth:360,background:`linear-gradient(160deg,${pool.darkBg},#1a6830)`,border:`2px solid ${hov?pool.color+"99":"#2a9444"}`,transition:"border-color .25s,transform .2s",transform:hov?"translateY(-5px)":"none",padding:"24px",position:"relative",overflow:"hidden"}}>
    {hov&&<div style={{position:"absolute",inset:0,background:`radial-gradient(ellipse at 50% 0%,${pool.glow} 0%,transparent 65%)`,opacity:.3,pointerEvents:"none"}}/>}

    {/* ── Big price badge ── */}
    <div style={{position:"absolute",top:0,left:0,zIndex:3,
      background:pool.color,color:"#000",padding:"2px 18px 8px",
      fontFamily:"'VT323',monospace",fontSize:46,lineHeight:1.15,
      boxShadow:`4px 4px 0 rgba(0,0,0,.35), 0 0 24px ${pool.glow}`,
    }}>${pool.entryUsd}</div>

    {/* Icon top right */}
    <div style={{position:"absolute",top:10,right:12,fontSize:24,zIndex:2}}>{pool.icon}</div>

    <div style={{marginBottom:14,marginTop:60}}>
      <div style={{fontSize:"clamp(10px,2vw,12px)",color:"#9de8b4",letterSpacing:2,marginBottom:2}}>{pool.label}</div>
      <div style={{
        color:pool.color,fontSize:"clamp(18px,3vw,26px)",
        fontFamily:"'VT323',monospace",lineHeight:1,marginBottom:2,
      }}>${Math.round(parseFloat(pool.poolEth||"0")*ethPrice).toLocaleString()} POOL</div>
      <div style={{fontSize:"clamp(13px,1.8vw,16px)",color:"#9de8b4",fontFamily:"'VT323',monospace"}}>entry: {pool.entryEth} ETH (~${pool.entryUsd})</div>
    </div>
    <div style={{background:"#0f5422",border:"1px solid #3a7a22",padding:"12px",textAlign:"center",marginBottom:16}}>
      <div style={{color:"#c0f0d0",fontSize:11,marginBottom:5}}>NEXT DRAW IN</div>
      <div style={{fontSize:"clamp(22px,6vw,30px)",letterSpacing:4,fontFamily:"'VT323',monospace",color:urgent?"#FF4444":soon?"#FFDD00":pool.color,animation:urgent?"blinkAnim .7s infinite":"none"}}>{fmtMs(msLeft)}</div>
    </div>
    <div style={{marginBottom:16,display:"flex",flexDirection:"column",gap:7}}>
      {[["IN POOL",`${pool.entries} tickets`],["JACKPOT",`${pool.jackpot} ETH`]].map(([l,v])=>(
        <div key={l} style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",padding:"4px 0",borderBottom:"1px solid #2a5a2a22"}}>
          <span style={{color:"#9de8b4",fontSize:9,fontFamily:"'Press Start 2P',monospace",flexShrink:0}}>{l}</span>
          <span style={{color:"#FFDD00",fontSize:14,fontFamily:"'VT323',monospace"}}>{v}</span>
        </div>
      ))}
    </div>
    {/* Draw status — compact single line, no wrap */}
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12,padding:"6px 0",borderTop:"1px solid #2a5a2a44",gap:6,flexWrap:"nowrap"}}>
      <span style={{color:pool.entries>=MIN_TICKETS?"#44FF44":"#FF9933",fontSize:9,fontFamily:"'Press Start 2P',monospace",whiteSpace:"nowrap"}}>
        {pool.entries>=MIN_TICKETS?"✅ GAME ON":"⚠ NEEDS "+(MIN_TICKETS-pool.entries)}
      </span>
      <span style={{color:"#9de8b4",fontSize:9,fontFamily:"'VT323',monospace",whiteSpace:"nowrap"}}>{Math.min(pool.entries,MIN_TICKETS)}/{MIN_TICKETS}</span>
    </div>
    {myOdds&&<div style={{background:`${pool.color}14`,border:`1px solid ${pool.color}33`,padding:"8px 10px",marginBottom:12,textAlign:"center"}}><span style={{color:pool.color,fontSize:11}}>🎟 {mc} ticket{mc>1?"s":""} · ~{myOdds}% chance per slot</span></div>}
    <div style={{display:"flex",gap:7}}>
      <button onClick={onMint} style={{flex:2,padding:"11px 4px",background:`linear-gradient(90deg,${pool.darkBg},${pool.color}22)`,color:pool.color,border:`2px solid ${pool.color}`,cursor:"pointer",fontSize:"clamp(8px,1.8vw,11px)",fontFamily:"'Press Start 2P',monospace",borderBottom:`4px solid ${pool.color}88`,outline:"none",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>🎟 BUY TICKET</button>
      <button onClick={onDraw} style={{flex:1,padding:"11px 0",background:"#0a0e18",color:"#FFDD00",border:"2px solid #FFDD0066",cursor:"pointer",fontSize:12,fontFamily:"'Press Start 2P',monospace",borderBottom:"4px solid #FFDD0044",outline:"none"}}>🎲 DRAW</button>
    </div>
  </div>);}

