/* ══════════════════════════════════════════════
   TICKET CARD
══════════════════════════════════════════════ */
function TicketCard({ticket,pool:poolOverride}){
  const pool=poolOverride||ALL_POOLS.find(p=>p.id===ticket.poolId)||POOLS[0];
  const ts=new Date(ticket.ts);
  const dateStr=ts.toLocaleDateString('en-GB',{day:'2-digit',month:'short'});
  const timeStr=ts.toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit'});
  return(
    <div className="ticket-card" style={{
      background:"linear-gradient(160deg,#0e3a0e,#145414)",
      border:`1px solid ${pool.color}44`,
      borderTop:"3px solid #FFD700",
      padding:"12px 10px",width:160,flexShrink:0,
      position:"relative",
    }}>
      {/* Pool header — VT323 wide, fits nicely */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
        <span style={{color:pool.color,fontSize:14,fontFamily:"'VT323',monospace",letterSpacing:1}}>{pool.icon} {pool.name}</span>
        <span style={{color:"#44FF44",background:"#44FF4418",padding:"1px 4px",fontSize:9,fontFamily:"monospace"}}>LIVE</span>
      </div>
      {/* Entry fee */}
      <div style={{
        textAlign:"center",padding:"8px 0",marginBottom:8,
        borderTop:`1px solid ${pool.color}33`,
        borderBottom:`1px solid ${pool.color}33`,
      }}>
        <div style={{color:pool.color,fontSize:28,fontFamily:"'VT323',monospace",lineHeight:1}}>${pool.entryUsd}</div>
        <div style={{color:"#9de8b4",fontSize:10,fontFamily:"'VT323',monospace",marginTop:2}}>{pool.entryEth} ETH</div>
      </div>
      {/* Draw info — monospace fits tight width */}
      <div style={{display:"flex",flexDirection:"column",gap:4,marginBottom:8}}>
        <div style={{display:"flex",justifyContent:"space-between",gap:4}}>
          <span style={{color:"#6aaa6a",fontSize:10,fontFamily:"'VT323',monospace"}}>DRAW</span>
          <span style={{color:"#9de8b4",fontSize:10,fontFamily:"'VT323',monospace",textAlign:"right"}}>{pool.label}</span>
        </div>
        <div style={{display:"flex",justifyContent:"space-between",gap:4}}>
          <span style={{color:"#6aaa6a",fontSize:10,fontFamily:"'VT323',monospace"}}>IN</span>
          <span style={{color:"#9de8b4",fontSize:10,fontFamily:"'VT323',monospace"}}>{dateStr} {timeStr}</span>
        </div>
      </div>
      {/* Ticket ID — plain monospace */}
      <div style={{borderTop:`1px solid ${pool.color}22`,paddingTop:6,color:"#6aaa6a",fontSize:9,fontFamily:"monospace",wordBreak:"break-all",lineHeight:1.4}}>{ticket.id}</div>
    </div>
  );
}

/* ══════════════════════════════════════════════
   TICKET SECTIONS — 3 groups × period dropdown × 4 stakes = 16 types
══════════════════════════════════════════════ */
function TicketSections({tickets,ethPrice,onMint,onDraw,msLeft,fmtMs}){
  const[sec1Period,setSec1Period]=useState("h1");
  const[sec2Period,setSec2Period]=useState("h6");
  const[sec3Period,setSec3Period]=useState("d1");

  const renderSection=(key,periodId,setPeriod)=>{
    const period=POOL_PERIODS.find(p=>p.pid===periodId)||POOL_PERIODS[0];
    // 4 stake options for this period
    const stakePools=POOL_STAKES.map(ps=>({
      ...period,...ps,
      id:`${period.pid}-${ps.entryUsd}`,
      offsetMin:0,
      poolEth:(parseFloat(ps.entryEth)*ps.entries).toFixed(4),
      jackpot:(parseFloat(ps.entryEth)*ps.entries*0.45).toFixed(5),
    }));
    // compute live ETH for each stake
    const stakeLive=stakePools.map(sp=>({
      ...sp,
      entryEth:(sp.entryUsd/ethPrice).toFixed(6),
      poolEth:((sp.entryUsd/ethPrice)*sp.entries).toFixed(4),
    }));

    return(
      <div key={key} style={{marginBottom:24,background:"#0f4a0f",border:"1px solid #2a7a22"}}>
        {/* Section header */}
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"12px 16px",background:"#145414",borderBottom:"2px solid #2a7a22",flexWrap:"wrap",gap:8}}>
          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <span style={{fontSize:16}}>{period.icon}</span>
            <select value={periodId} onChange={e=>setPeriod(e.target.value)} style={{
              background:"#0f5422",color:period.color,border:`2px solid ${period.color}`,
              padding:"6px 10px",fontSize:9,fontFamily:"'Press Start 2P',monospace",
              cursor:"pointer",outline:"none",
            }}>
              {POOL_PERIODS.map(pp=>(
                <option key={pp.pid} value={pp.pid}>{pp.icon} {pp.name} — {pp.label}</option>
              ))}
            </select>
            <span style={{color:"#9de8b4",fontSize:9,fontFamily:"'Press Start 2P',monospace"}}>
              next draw: {fmtMs(msLeft({intervalH:period.intervalH,offsetMin:0}))}
            </span>
          </div>
        </div>

        {/* 4 stake cards side by side */}
        <div style={{display:"flex",gap:0,flexWrap:"wrap"}}>
          {stakeLive.map(pool=>{
            const myTickets=tickets.filter(t=>t.poolId===pool.id);
            return(
              <div key={pool.id} style={{
                flex:"1 1 160px",
                borderRight:"1px solid #2a7a22",
                padding:"14px",
                background:myTickets.length>0?`${pool.color}08`:"transparent",
              }}>
                {/* Stake amount */}
                <div style={{textAlign:"center",marginBottom:10}}>
                  <div style={{color:pool.color,fontSize:28,fontFamily:"'VT323',monospace",lineHeight:1}}>${pool.entryUsd}</div>
                  <div style={{color:"#9de8b4",fontSize:8,fontFamily:"'Press Start 2P',monospace",marginTop:3}}>{pool.entryEth} ETH</div>
                </div>
                {/* Pool stats */}
                <div style={{fontSize:8,fontFamily:"'Press Start 2P',monospace",marginBottom:10,display:"flex",flexDirection:"column",gap:3}}>
                  <div style={{display:"flex",justifyContent:"space-between"}}>
                    <span style={{color:"#6aaa6a"}}>POOL</span>
                    <span style={{color:"#9de8b4"}}>{pool.entries} entries</span>
                  </div>
                  <div style={{display:"flex",justifyContent:"space-between"}}>
                    <span style={{color:"#6aaa6a"}}>JACKPOT</span>
                    <span style={{color:"#FFD700"}}>{pool.jackpot} ETH</span>
                  </div>
                  {myTickets.length>0&&<div style={{color:"#44FF44",fontSize:8}}>✓ {myTickets.length} entr{myTickets.length===1?"y":"ies"}</div>}
                </div>
                {/* Enter button */}
                <button onClick={()=>onMint(pool)} style={{
                  width:"100%",padding:"8px 0",
                  background:myTickets.length>0?`${pool.color}22`:"#0a2010",
                  color:pool.color,border:`1px solid ${pool.color}`,
                  cursor:"pointer",fontSize:9,
                  fontFamily:"'Press Start 2P',monospace",outline:"none",
                }}>
                  {myTickets.length>0?"+ MORE":"ENTER"}
                </button>
                {myTickets.length>0&&(
                  <button onClick={()=>onDraw(pool)} style={{
                    width:"100%",padding:"6px 0",marginTop:4,
                    background:"transparent",color:"#FFDD00",
                    border:"1px solid #FFDD0044",cursor:"pointer",
                    fontSize:8,fontFamily:"'Press Start 2P',monospace",outline:"none",
                  }}>DRAW</button>
                )}
              </div>
            );
          })}
        </div>

        {/* My tickets for this period */}
        {tickets.filter(t=>t.poolId.startsWith(period.pid+"-")).length>0&&(
          <div style={{borderTop:"1px solid #2a7a22",padding:"12px 14px"}}>
            <div style={{color:"#9de8b4",fontSize:9,fontFamily:"'Press Start 2P',monospace",marginBottom:10}}>YOUR ENTRIES</div>
            <div style={{display:"flex",gap:10,overflowX:"auto",paddingBottom:6}}>
              {tickets.filter(t=>t.poolId.startsWith(period.pid+"-")).map(t=>{
                const pool=ALL_POOLS.find(p=>p.id===t.poolId)||stakeLive[0];
                return <TicketCard key={t.id} ticket={t} pool={pool}/>;
              })}
            </div>
          </div>
        )}
      </div>
    );
  };

  return(
    <div>
      {renderSection("s1",sec1Period,setSec1Period)}
      {renderSection("s2",sec2Period,setSec2Period)}
      {renderSection("s3",sec3Period,setSec3Period)}
    </div>
  );
}



/* ══════════════════════════════════════════════
   WALLET SECTION (used in Profile tab)
══════════════════════════════════════════════ */
function WalletSection(){
  // Access wagmi hooks for wallet state in profile
  const[addr,setAddr]=useState("");
  const[bal,setBal]=useState("0.0000");
  useEffect(()=>{
    // Read from wagmi via window if available — no extra imports needed
    try{
      const w=document.querySelector("[data-wallet-address]");
      if(w)setAddr(w.getAttribute("data-wallet-address")||"");
    }catch(e){}
  },[]);

  return(
    <div style={{background:"linear-gradient(135deg,#0a2a14,#145414)",border:"2px solid #1BF26A44",padding:"20px"}}>
      <div style={{color:"#1BF26A",fontSize:10,fontFamily:"'Press Start 2P',monospace",marginBottom:14,letterSpacing:1}}>
        ⚡ WALLET
      </div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:10}}>
        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          <div style={{color:"#9de8b4",fontSize:9,fontFamily:"'Press Start 2P',monospace"}}>CONNECTED VIA ABSTRACT GLOBAL WALLET</div>
          <div style={{color:"#1BF26A",fontSize:12,fontFamily:"monospace"}}>
            {addr||"Connect wallet to see address"}
          </div>
        </div>
        <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
          <button
            onClick={()=>typeof window!=="undefined"&&window.location.reload()}
            style={{
              background:"#0a2010",color:"#1BF26A",
              border:"1px solid #1BF26A",padding:"8px 12px",
              cursor:"pointer",fontSize:9,
              fontFamily:"'Press Start 2P',monospace",outline:"none",
            }}>
            SWITCH WALLET
          </button>
          <button
            onClick={()=>{
              // Trigger disconnect via DOM event
              document.dispatchEvent(new CustomEvent("wheelpool-disconnect"));
            }}
            style={{
              background:"#2a0808",color:"#FF4444",
              border:"1px solid #FF4444",padding:"8px 12px",
              cursor:"pointer",fontSize:9,
              fontFamily:"'Press Start 2P',monospace",outline:"none",
            }}>
            LOG OUT
          </button>
        </div>
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════
   MY PROFILE / MY TICKETS
══════════════════════════════════════════════ */

// Level system based on total points earned
function getLevel(pts){
  if(pts>=10000)return{name:"LEGEND",  icon:"👑",color:"#FFD700",next:null};
  if(pts>=5000) return{name:"ELITE",   icon:"💎",color:"#AA44FF",next:10000};
  if(pts>=2000) return{name:"PRO",     icon:"🔥",color:"#FF6633",next:5000};
  if(pts>=500)  return{name:"PLAYER",  icon:"⚡",color:"#00DDAA",next:2000};
  return        {name:"ROOKIE",        icon:"🎡",color:"#9de8b4",next:500};
}

const ACHIEVEMENTS=[
  {id:"first-entry", icon:"🎟",name:"FIRST ENTRY",   desc:"Enter your first pool",          pts:50,  check:(t,w,wins)=>t.length>=1},
  {id:"first-win",   icon:"🏆",name:"FIRST WIN",     desc:"Win an ETH prize",               pts:200, check:(t,w,wins)=>wins>=1},
  {id:"100-points",  icon:"⭐",name:"100 POINTS",    desc:"Earn 100 WHEEL points",          pts:0,   check:(t,w,wins)=>w>=100},
  {id:"500-points",  icon:"🌟",name:"500 POINTS",    desc:"Earn 500 WHEEL points",          pts:100, check:(t,w,wins)=>w>=500},
  {id:"5-entries",   icon:"🎯",name:"HIGH ROLLER",   desc:"Hold 5+ active tickets",         pts:150, check:(t,w,wins)=>t.length>=5},
  {id:"3-pools",     icon:"🌊",name:"POOL HOPPER",   desc:"Enter 3 different pool types",   pts:100, check:(t,w,wins)=>{const ids=new Set(t.map(x=>x.poolId?.split("-")[0]));return ids.size>=3;}},
  {id:"weekly",      icon:"📅",name:"WEEKLY PLAYER", desc:"Enter the weekly draw",          pts:200, check:(t,w,wins)=>t.some(x=>x.poolId?.startsWith("w1"))},
  {id:"share",       icon:"📢",name:"AMBASSADOR",    desc:"Share WheelPool with friends",   pts:100, check:(t,w,wins,shared)=>shared},
];

function MyProfile({tickets,wheelPoints,activePerks,addPoints,ethPrice,onMint,onDraw,ms,fmtMs}){
  const[shared,setShared]=useState(false);
  const[shareFlash,setShareFlash]=useState(false);
  const[claimedAch,setClaimedAch]=useState([]);
  const[cancelModal,setCancelModal]=useState(null); // {periodId, periodLabel, periodColor, poolLabel}

  const level=getLevel(wheelPoints);
  const totalEntries=tickets.length;
  // Simulated stats for demo
  const totalWins=Math.floor(totalEntries*0.1);
  const winRate=totalEntries>0?((totalWins/totalEntries)*100).toFixed(1):"0.0";
  const totalEthWon=(totalWins*0.025).toFixed(4);
  const activeTickets=tickets; // all current tickets are active

  const handleShare=()=>{
    navigator.clipboard?.writeText("Check out WheelPool — prize pool dApp on Abstract Chain! https://wheelpool.vercel.app").catch(()=>{});
    if(!shared){
      addPoints(100);
      setShared(true);
      setShareFlash(true);
      setTimeout(()=>setShareFlash(false),2000);
    }
  };

  const claimAch=(ach)=>{
    if(claimedAch.includes(ach.id)||!ach.pts)return;
    addPoints(ach.pts);
    setClaimedAch(p=>[...p,ach.id]);
  };

  const PERIOD_LABELS={"h1":"HOURLY","h6":"6H","h12":"12H","d1":"DAILY","w1":"WEEKLY"};

  return(
    <div style={{display:"flex",flexDirection:"column",gap:28}}>

      {/* ── PROFILE HEADER ────────────────────── */}
      <div style={{
        background:"linear-gradient(135deg,#0a2a0a,#1a4a1a,#0a3a14)",
        border:"2px solid #1BF26A44",padding:"24px",
        display:"flex",gap:20,flexWrap:"wrap",alignItems:"center",
      }}>
        {/* Avatar — level icon */}
        <div style={{
          width:72,height:72,borderRadius:"50%",flexShrink:0,
          background:`linear-gradient(135deg,${level.color}22,${level.color}44)`,
          border:`3px solid ${level.color}`,
          display:"flex",alignItems:"center",justifyContent:"center",
          fontSize:32,
        }}>{level.icon}</div>

        {/* Identity */}
        <div style={{flex:1,minWidth:180}}>
          <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:4,flexWrap:"wrap"}}>
            <span style={{color:level.color,fontSize:14,fontFamily:"'Press Start 2P',monospace"}}>{level.name}</span>
            <span style={{color:"#6aaa6a",fontSize:9,fontFamily:"'Press Start 2P',monospace"}}>WHEELPOOL MEMBER</span>
          </div>
          {level.next&&(
            <div style={{marginBottom:8}}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
                <span style={{color:"#6aaa6a",fontSize:8,fontFamily:"'Press Start 2P',monospace"}}>PROGRESS TO NEXT LEVEL</span>
                <span style={{color:level.color,fontSize:8,fontFamily:"'Press Start 2P',monospace"}}>{wheelPoints}/{level.next}</span>
              </div>
              <div style={{height:6,background:"#0a1a0a",overflow:"hidden",borderRadius:3}}>
                <div style={{width:`${Math.min(100,(wheelPoints/(level.next||1))*100)}%`,height:"100%",background:level.color,transition:"width .5s"}}/>
              </div>
            </div>
          )}
          <div style={{color:"#FFDD00",fontSize:18,fontFamily:"'VT323',monospace"}}>🎡 {wheelPoints.toLocaleString()} WHEEL POINTS</div>
        </div>

        {/* Share button */}
        <button onClick={handleShare} style={{
          background:shareFlash?"#1a3a00":shared?"#0a1a0a":"linear-gradient(135deg,#1a3a0a,#2a5a14)",
          color:shared?"#44FF44":"#1BF26A",
          border:`2px solid ${shared?"#44FF44":"#1BF26A"}`,
          padding:"10px 16px",cursor:shared?"default":"pointer",
          fontSize:9,fontFamily:"'Press Start 2P',monospace",
          outline:"none",letterSpacing:1,
          transition:"all .3s",
          boxShadow:shareFlash?"0 0 20px rgba(27,242,106,.5)":"none",
        }}>
          {shared?"✓ SHARED +100 PTS":"📢 SHARE & EARN +100 PTS"}
        </button>
      </div>

      {/* ── STATS ROW ─────────────────────────── */}
      <div style={{display:"flex",gap:0,flexWrap:"wrap",background:"#0a2a0a",border:"1px solid #2a5a2a"}}>
        {[
          ["ENTRIES",     totalEntries.toString(),         "#1BF26A"],
          ["WINS",        totalWins.toString(),            "#FFD700"],
          ["WIN RATE",    `${winRate}%`,                   "#00DDAA"],
          ["ETH WON",     `${totalEthWon}`,                "#FF6633"],
          ["POINTS",      wheelPoints.toLocaleString(),    "#FFDD00"],
        ].map(([l,v,c],i)=>(
          <div key={l} style={{
            flex:"1 1 80px",padding:"14px",textAlign:"center",
            borderRight:i<4?"1px solid #2a5a2a":"none",
          }}>
            <div style={{color:"#6aaa6a",fontSize:8,fontFamily:"'Press Start 2P',monospace",marginBottom:6}}>{l}</div>
            <div style={{color:c,fontSize:18,fontFamily:"'VT323',monospace"}}>{v}</div>
          </div>
        ))}
      </div>

      {/* ── ACTIVE TICKETS ────────────────────── */}
      <div>
        <div style={{color:"#FFDD00",fontSize:11,fontFamily:"'Press Start 2P',monospace",marginBottom:14}}>🎟 ACTIVE ENTRIES</div>
        {activeTickets.length===0?(
          <div style={{background:"#0a2a0a",border:"1px dashed #2a5a2a",padding:"24px",textAlign:"center"}}>
            <div style={{color:"#6aaa6a",fontSize:9,fontFamily:"'Press Start 2P',monospace",lineHeight:2}}>No active entries yet</div>
          </div>
        ):(
          <div style={{display:"flex",flexDirection:"column",gap:20}}>
            {[
              {pid:"h1",label:"HOURLY",  icon:"🎡",color:"#FF6633"},
              {pid:"d1",label:"DAILY",   icon:"⚡",color:"#FFDD00"},
              {pid:"w1",label:"WEEKLY",  icon:"👑",color:"#AA44FF"},
            ].map(period=>{
              const periodTickets=activeTickets.filter(t=>t.poolId?.startsWith(period.pid+"-"));
              if(periodTickets.length===0)return null;
              const totalMyTickets=periodTickets.length;
              const avgEntries=Math.round(periodTickets.reduce((a,t)=>{
                const s=POOL_STAKES.find(s=>s.entryUsd===parseInt(t.poolId?.split("-")[1]));
                return a+(s?.entries||47);
              },0)/totalMyTickets);
              const myOdds=Math.min(99,(totalMyTickets/avgEntries*100)).toFixed(1);
              return(
                <div key={period.pid}>
                  <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8,flexWrap:"wrap",gap:8}}>
                    <div style={{display:"flex",alignItems:"center",gap:8}}>
                      <span style={{fontSize:14}}>{period.icon}</span>
                      <span style={{color:period.color,fontSize:11,fontFamily:"'Press Start 2P',monospace"}}>{period.label}</span>
                      <span style={{color:period.color,fontSize:11,fontFamily:"'VT323',monospace"}}>
                        🎟 {totalMyTickets} ticket{totalMyTickets>1?"s":""}
                      </span>
                    </div>
                    <div style={{display:"flex",alignItems:"center",gap:8}}>
                      <span style={{color:"#9de8b4",fontSize:10,fontFamily:"'VT323',monospace"}}>~{myOdds}% chance</span>
                      <button
                        onClick={()=>setCancelModal({
                          periodId:period.pid,
                          periodLabel:period.label,
                          periodColor:period.color,
                          periodIcon:period.icon,
                        })}
                        style={{
                          background:"transparent",color:"#FF6633",
                          border:"1px solid #FF663366",
                          padding:"4px 10px",cursor:"pointer",
                          fontSize:8,fontFamily:"'Press Start 2P',monospace",
                          outline:"none",
                        }}>
                        ✕ CANCEL
                      </button>
                    </div>
                  </div>
                  <div style={{display:"flex",gap:10,overflowX:"auto",paddingBottom:6}}>
                    {periodTickets.map(t=>{
                      const pid=t.poolId?.split("-")[0]||"h1";
                      const per=POOL_PERIODS.find(p=>p.pid===pid)||POOL_PERIODS[0];
                      const stake=POOL_STAKES.find(s=>s.entryUsd===parseInt(t.poolId?.split("-")[1]))||POOL_STAKES[0];
                      const liveEth=(stake.entryUsd/ethPrice).toFixed(5);
                      const pool={...per,...stake,id:t.poolId,entryEth:liveEth,poolEth:(parseFloat(liveEth)*stake.entries).toFixed(4),glow:per.color+"44",offsetMin:0};
                      return <TicketCard key={t.id} ticket={t} pool={pool}/>;
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* ── TICKET HISTORY (simulated) ─────────── */}
      <div>
        <div style={{color:"#FFDD00",fontSize:11,fontFamily:"'Press Start 2P',monospace",marginBottom:14}}>📜 DRAW HISTORY</div>
        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          {[
            {id:"WP-H1-0022",pool:"HOURLY $2",  result:"POINTS", pts:100, ts:Date.now()-3600000},
            {id:"WP-D1-0021",pool:"DAILY $5",   result:"POINTS", pts:250, ts:Date.now()-86400000},
            {id:"WP-H1-0020",pool:"HOURLY $2",  result:"WIN",    eth:"0.0169",ts:Date.now()-7200000},
            {id:"WP-W1-0019",pool:"WEEKLY $25", result:"POINTS", pts:1250,ts:Date.now()-604800000},
            {id:"WP-H1-0018",pool:"HOURLY $5",  result:"POINTS", pts:250, ts:Date.now()-10800000},
          ].map((h,i)=>{
            const d=new Date(h.ts);
            const isWin=h.result==="WIN";
            return(
              <div key={i} style={{
                display:"flex",alignItems:"center",gap:12,
                background:"#0a2a0a",border:"1px solid #1a4a1a",
                padding:"10px 14px",flexWrap:"wrap",
              }}>
                <span style={{fontSize:16,flexShrink:0}}>{isWin?"🏆":"🎡"}</span>
                <div style={{flex:"1 1 120px"}}>
                  <div style={{color:"#9de8b4",fontSize:9,fontFamily:"'Press Start 2P',monospace"}}>{h.pool}</div>
                  <div style={{color:"#6aaa6a",fontSize:8,fontFamily:"monospace",marginTop:2}}>{d.toLocaleDateString("en-GB")} {d.toLocaleTimeString("en-GB",{hour:"2-digit",minute:"2-digit"})}</div>
                </div>
                <div style={{textAlign:"right",flexShrink:0}}>
                  {isWin?(
                    <div style={{color:"#FFD700",fontSize:16,fontFamily:"'VT323',monospace"}}>+{h.eth} ETH</div>
                  ):(
                    <div style={{color:"#FFDD00",fontSize:16,fontFamily:"'VT323',monospace"}}>+{h.pts} PTS</div>
                  )}
                  <div style={{
                    fontSize:8,fontFamily:"'Press Start 2P',monospace",
                    color:isWin?"#FFD700":"#9de8b4",
                  }}>{isWin?"WIN":"POINTS EARNED"}</div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* ── ACHIEVEMENTS ──────────────────────── */}
      <div>
        <div style={{color:"#FFDD00",fontSize:11,fontFamily:"'Press Start 2P',monospace",marginBottom:14}}>🏅 ACHIEVEMENTS</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(220px,1fr))",gap:10}}>
          {ACHIEVEMENTS.map(ach=>{
            const unlocked=ach.check(tickets,wheelPoints,totalWins,shared);
            const claimed=claimedAch.includes(ach.id);
            return(
              <div key={ach.id} style={{
                background:unlocked?"linear-gradient(135deg,#1a3a0a,#1a4a14)":"#0a1a0a",
                border:`1px solid ${unlocked?"#44FF44":"#2a4a2a"}`,
                padding:"12px",opacity:unlocked?1:0.5,
                display:"flex",gap:10,alignItems:"center",
              }}>
                <span style={{fontSize:20,flexShrink:0}}>{ach.icon}</span>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{color:unlocked?"#44FF44":"#6aaa6a",fontSize:8,fontFamily:"'Press Start 2P',monospace",marginBottom:3}}>{ach.name}</div>
                  <div style={{color:"#9de8b4",fontSize:9,fontFamily:"'VT323',monospace"}}>{ach.desc}</div>
                  {ach.pts>0&&<div style={{color:"#FFDD00",fontSize:9,fontFamily:"'VT323',monospace",marginTop:2}}>+{ach.pts} pts bonus</div>}
                </div>
                {unlocked&&ach.pts>0&&!claimed&&(
                  <button onClick={()=>claimAch(ach)} style={{
                    background:"#1a3a00",color:"#44FF44",
                    border:"1px solid #44FF44",padding:"4px 8px",
                    cursor:"pointer",fontSize:7,
                    fontFamily:"'Press Start 2P',monospace",outline:"none",flexShrink:0,
                  }}>CLAIM</button>
                )}
                {claimed&&<span style={{color:"#44FF44",fontSize:14,flexShrink:0}}>✓</span>}
                {unlocked&&!ach.pts&&<span style={{color:"#44FF44",fontSize:14,flexShrink:0}}>✓</span>}
              </div>
            );
          })}
        </div>
      </div>

      {/* ── REFERRAL ──────────────────────────── */}
      <div style={{background:"#0a2a0a",border:"1px solid #2a5a2a",padding:"20px"}}>
        <div style={{color:"#FFDD00",fontSize:11,fontFamily:"'Press Start 2P',monospace",marginBottom:8}}>🔗 YOUR REFERRAL LINK</div>
        <div style={{color:"#6aaa6a",fontSize:9,fontFamily:"'Press Start 2P',monospace",marginBottom:12,lineHeight:2}}>
          Share your link and earn 500 WHEEL points when a friend makes their first entry
        </div>
        <div style={{
          display:"flex",gap:8,flexWrap:"wrap",
          background:"#061406",border:"1px solid #2a5a2a",padding:"10px 12px",
          color:"#9de8b4",fontSize:10,fontFamily:"monospace",marginBottom:10,
          wordBreak:"break-all",
        }}>
          https://wheelpool.vercel.app?ref=0x1234...abcd
        </div>
        <button onClick={handleShare} style={{
          background:"#1a3a0a",color:"#1BF26A",
          border:"1px solid #1BF26A44",padding:"8px 16px",
          cursor:"pointer",fontSize:9,
          fontFamily:"'Press Start 2P',monospace",outline:"none",
        }}>📋 COPY LINK</button>
      </div>

      {/* Cancel Modal */}
      {cancelModal&&<CancelModal
        modal={cancelModal}
        tickets={activeTickets.filter(t=>t.poolId?.startsWith(cancelModal.periodId+"-"))}
        pools={POOLS}
        ethPrice={ethPrice}
        onClose={()=>setCancelModal(null)}
        onConfirm={(ids)=>{
          // Remove cancelled tickets from state
          // In production: call WheelPool.cancelTicket() per ticket
          const newTickets=tickets.filter(t=>!ids.includes(t.id));
          // Update parent tickets state via prop
          setCancelModal(null);
          alert(`${ids.length} ticket${ids.length>1?"s":""} cancelled. In production this would call the smart contract.`);
        }}
      />}
    </div>
  );
}

/* ══════════════════════════════════════════════
   CANCEL MODAL
══════════════════════════════════════════════ */
function CancelModal({modal,tickets,pools,ethPrice,onClose,onConfirm}){
  const[selected,setSelected]=useState(tickets.map(t=>t.id));

  const CANCEL_REFUND_PCT   = 78;
  const CANCEL_WHEELPOT_PCT = 2;
  const CANCEL_TREASURY_PCT = 20;

  const toggle=(id)=>setSelected(s=>
    s.includes(id) ? s.filter(x=>x!==id) : [...s,id]
  );
  const selectAll =()=>setSelected(tickets.map(t=>t.id));
  const deselectAll=()=>setSelected([]);

  // Compute fees for selected tickets
  const selectedTickets=tickets.filter(t=>selected.includes(t.id));
  const totalEth=selectedTickets.reduce((sum,t)=>{
    const pid=t.poolId?.split("-")[0]||"h1";
    const nominalUsd=parseInt(t.poolId?.split("-")[1]||"2");
    return sum+(nominalUsd/ethPrice);
  },0);
  const refundEth  =(totalEth*CANCEL_REFUND_PCT/100).toFixed(6);
  const wheelPotEth=(totalEth*CANCEL_WHEELPOT_PCT/100).toFixed(6);
  const treasuryEth=(totalEth*CANCEL_TREASURY_PCT/100).toFixed(6);
  const refundUsd  =(parseFloat(refundEth)*ethPrice).toFixed(2);

  const PERIOD_LABELS={"h1":"HOURLY","d1":"DAILY","w1":"WEEKLY"};

  return(
    <div style={{
      position:"fixed",inset:0,background:"rgba(0,0,0,.88)",
      display:"flex",alignItems:"center",justifyContent:"center",
      zIndex:600,padding:"20px",
    }} onClick={onClose}>
      <div onClick={e=>e.stopPropagation()} style={{
        background:"#0e2a0e",border:"2px solid #FF6633",
        padding:"24px",maxWidth:480,width:"100%",
        maxHeight:"85vh",overflowY:"auto",
        boxShadow:"0 0 40px rgba(255,102,51,.3)",
        fontFamily:"'Press Start 2P',monospace",
      }}>
        {/* Header */}
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
          <div>
            <div style={{color:"#FF6633",fontSize:11,marginBottom:4}}>
              {modal.periodIcon} CANCEL {modal.periodLabel} TICKETS
            </div>
            <div style={{color:"#9de8b4",fontSize:9,fontFamily:"'VT323',monospace"}}>
              22% cancellation fee · 78% refunded
            </div>
          </div>
          <button onClick={onClose} style={{
            background:"transparent",color:"#FF4444",border:"1px solid #FF4444",
            width:28,height:28,cursor:"pointer",fontSize:14,outline:"none",
          }}>✕</button>
        </div>

        {/* Fee breakdown banner */}
        <div style={{
          background:"#1a0800",border:"1px solid #FF663344",
          padding:"10px 14px",marginBottom:16,
          display:"flex",gap:0,flexWrap:"wrap",
        }}>
          {[
            ["REFUND","78%","#44FF44"],
            ["WHEELPOT","2%","#FFD700"],
            ["TREASURY","20%","#FF6633"],
          ].map(([l,v,c])=>(
            <div key={l} style={{flex:"1 1 80px",textAlign:"center",padding:"4px 0"}}>
              <div style={{color:"#9de8b4",fontSize:8,marginBottom:3}}>{l}</div>
              <div style={{color:c,fontSize:16,fontFamily:"'VT323',monospace"}}>{v}</div>
            </div>
          ))}
        </div>

        {/* Select all / none */}
        <div style={{display:"flex",gap:8,marginBottom:12}}>
          <button onClick={selectAll} style={{
            background:"#0a2010",color:"#44FF44",border:"1px solid #44FF4444",
            padding:"5px 10px",cursor:"pointer",fontSize:8,outline:"none",
          }}>SELECT ALL</button>
          <button onClick={deselectAll} style={{
            background:"#0a2010",color:"#9de8b4",border:"1px solid #44FF4422",
            padding:"5px 10px",cursor:"pointer",fontSize:8,outline:"none",
          }}>DESELECT ALL</button>
          <span style={{color:"#9de8b4",fontSize:10,fontFamily:"'VT323',monospace",marginLeft:"auto",alignSelf:"center"}}>
            {selected.length}/{tickets.length} selected
          </span>
        </div>

        {/* Ticket list */}
        <div style={{display:"flex",flexDirection:"column",gap:6,marginBottom:16}}>
          {tickets.length===0?(
            <div style={{color:"#6aaa6a",fontSize:9,textAlign:"center",padding:16}}>
              No tickets in this period
            </div>
          ):tickets.map(t=>{
            const nominalUsd=parseInt(t.poolId?.split("-")[1]||"2");
            const entryEth=(nominalUsd/ethPrice).toFixed(6);
            const isSelected=selected.includes(t.id);
            const ts=new Date(t.ts);
            return(
              <div
                key={t.id}
                onClick={()=>toggle(t.id)}
                style={{
                  display:"flex",alignItems:"center",gap:10,
                  background:isSelected?"#1a0a0a":"#0a1a0a",
                  border:`1px solid ${isSelected?"#FF6633":"#2a5a2a"}`,
                  padding:"10px 12px",cursor:"pointer",
                  transition:"all .15s",
                }}>
                {/* Checkbox */}
                <div style={{
                  width:18,height:18,border:`2px solid ${isSelected?"#FF6633":"#44FF44"}`,
                  background:isSelected?"#FF6633":"transparent",
                  display:"flex",alignItems:"center",justifyContent:"center",
                  flexShrink:0,fontSize:12,
                }}>
                  {isSelected&&"✓"}
                </div>
                {/* Ticket info */}
                <div style={{flex:1,minWidth:0}}>
                  <div style={{color:"#9de8b4",fontSize:9,marginBottom:2}}>{t.id}</div>
                  <div style={{color:"#6aaa6a",fontSize:8,fontFamily:"monospace"}}>
                    {ts.toLocaleDateString("en-GB")} {ts.toLocaleTimeString("en-GB",{hour:"2-digit",minute:"2-digit"})}
                  </div>
                </div>
                {/* Amount */}
                <div style={{textAlign:"right",flexShrink:0}}>
                  <div style={{color:"#FF6633",fontSize:14,fontFamily:"'VT323',monospace"}}>${nominalUsd}</div>
                  <div style={{color:"#9de8b4",fontSize:8,fontFamily:"'VT323',monospace"}}>{entryEth} ETH</div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Refund summary */}
        {selected.length>0&&(
          <div style={{
            background:"#0a1a0a",border:"1px solid #44FF4433",
            padding:"12px 14px",marginBottom:16,
          }}>
            <div style={{color:"#FFDD00",fontSize:9,marginBottom:10}}>CANCELLATION SUMMARY</div>
            {[
              ["TICKETS",`${selected.length} selected`,"#9de8b4"],
              ["TOTAL VALUE",`${totalEth.toFixed(6)} ETH`,"#9de8b4"],
              ["YOU RECEIVE",`${refundEth} ETH (~$${refundUsd})`,"#44FF44"],
              ["→ WHEELPOT",`${wheelPotEth} ETH`,"#FFD700"],
              ["→ TREASURY",`${treasuryEth} ETH`,"#FF6633"],
            ].map(([l,v,c])=>(
              <div key={l} style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",marginBottom:8,gap:8}}>
                <span style={{color:"#6aaa6a",fontSize:9,fontFamily:"'Press Start 2P',monospace",flexShrink:0}}>{l}</span>
                <span style={{color:c,fontSize:18,fontFamily:"'VT323',monospace",textAlign:"right"}}>{v}</span>
              </div>
            ))}
            <div style={{
              marginTop:8,paddingTop:8,borderTop:"1px solid #FF663322",
              color:"#9de8b4",fontSize:8,lineHeight:2,
            }}>
              ⚠ WheelPot tickets are kept regardless of cancellation.
              Cannot cancel within 10 minutes of draw time.
            </div>
          </div>
        )}

        {/* Action buttons */}
        <div style={{display:"flex",gap:8}}>
          <button
            onClick={()=>selected.length>0&&onConfirm(selected)}
            disabled={selected.length===0}
            style={{
              flex:1,padding:"12px 0",
              background:selected.length>0?"#2a0808":"#0a0a0a",
              color:selected.length>0?"#FF4444":"#333",
              border:`1px solid ${selected.length>0?"#FF4444":"#222"}`,
              cursor:selected.length>0?"pointer":"default",
              fontSize:9,outline:"none",
              borderBottom:selected.length>0?"3px solid #FF6633":"3px solid #222",
            }}>
            {selected.length>0
              ?`CANCEL ${selected.length} TICKET${selected.length>1?"S":""} →`
              :"SELECT TICKETS"}
          </button>
          <button onClick={onClose} style={{
            flex:1,padding:"12px 0",
            background:"transparent",color:"#9de8b4",
            border:"1px solid #2a5a2a",
            cursor:"pointer",fontSize:9,outline:"none",
          }}>KEEP TICKETS</button>
        </div>
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════
   WHEELPOT MODAL — details popup
══════════════════════════════════════════════ */
